const express = require('express');
const handlebars = require('handlebars');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());

// SECURE: Precompile templates at application startup
const templates = new Map();

function loadTemplates() {
  const templateDir = path.join(__dirname, 'templates');
  const templateFiles = fs.readdirSync(templateDir);

  templateFiles.forEach(file => {
    if (file.endsWith('.hbs')) {
      const templateSource = fs.readFileSync(
        path.join(templateDir, file),
        'utf8'
      );

      // Precompile template (done once at startup)
      const compiledTemplate = handlebars.compile(templateSource, {
        strict: true,           // Fail on undefined variables
        noEscape: false,        // Always escape output
        compat: false,          // Disable legacy features
        preventIndent: true
      });

      templates.set(file.replace('.hbs', ''), compiledTemplate);
    }
  });

  console.log(`Loaded ${templates.size} precompiled templates`);
}

loadTemplates();

// Whitelist allowed template data fields
const ALLOWED_FIELDS = new Set([
  'userName', 'email', 'orderId', 'productName', 'amount'
]);

function sanitizeTemplateData(data) {
  const sanitized = {};

  for (const [key, value] of Object.entries(data)) {
    // Only allow whitelisted fields
    if (!ALLOWED_FIELDS.has(key)) {
      throw new Error(`Invalid template variable: ${key}`);
    }

    // Ensure value is a safe primitive type
    if (typeof value !== 'string' && typeof value !== 'number') {
      throw new Error(`Invalid value type for ${key}`);
    }

    // Additional sanitization for strings
    if (typeof value === 'string') {
      // Remove any attempt to inject template syntax
      if (value.includes('{{') || value.includes('}}')) {
        throw new Error('Template syntax not allowed in data');
      }
    }

    sanitized[key] = value;
  }

  return sanitized;
}

// SECURE endpoint using precompiled template
app.post('/render/email', (req, res) => {
  try {
    // Get template name (from predefined set, NOT user input)
    const templateName = 'order_confirmation'; // Hardcoded, safe

    // Get template data
    const rawData = req.body;

    // Sanitize and validate data
    const templateData = sanitizeTemplateData(rawData);

    // Retrieve precompiled template
    const template = templates.get(templateName);
    if (!template) {
      return res.status(404).json({ error: 'Template not found' });
    }

    // Render with sanitized data (no compilation happening here)
    const rendered = template(templateData);

    res.json({ html: rendered });

  } catch (error) {
    console.error('Template rendering error:', error);
    res.status(400).json({ error: error.message });
  }
});

