import freemarker.template.Configuration;
import freemarker.template.Template;
import freemarker.template.TemplateException;
import freemarker.core.HTMLOutputFormat;
import freemarker.template.TemplateExceptionHandler;
import org.springframework.context.annotation.Bean;
import org.springframework.web.bind.annotation.*;

import java.io.StringWriter;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.Set;
import java.util.regex.Pattern;

@RestController
@RequestMapping("/api")
public class SecureTemplateController {

    private final Configuration freemarkerConfig;
    private final Set<String> allowedTemplateVars = Set.of(
        "userName", "orderId", "productName", "amount", "date"
    );

    // Pattern to detect template injection attempts
    private static final Pattern TEMPLATE_INJECTION_PATTERN = 
        Pattern.compile(".*[<$]\\{.*\\}.*|.*#\\{.*\\}.*|.*\\$\\{.*\\}.*");

    public SecureTemplateController() {
        this.freemarkerConfig = createSecureConfiguration();
    }

    /**
     * Create secure Freemarker configuration
     */
    @Bean
    public Configuration createSecureConfiguration() {
        Configuration cfg = new Configuration(Configuration.VERSION_2_3_31);

        try {
            // Load templates from classpath (not filesystem)
            cfg.setClassLoaderForTemplateLoading(
                getClass().getClassLoader(), 
                "/templates"
            );

            // CRITICAL SECURITY SETTINGS

            // 1. Disable dangerous built-ins
            cfg.setAPIBuiltinEnabled(false);  // Prevents ?api access to Java objects
            cfg.setLogTemplateExceptions(false);

            // 2. Set strict HTML auto-escaping
            cfg.setOutputFormat(HTMLOutputFormat.INSTANCE);
            cfg.setAutoEscapingPolicy(Configuration.ENABLE_IF_SUPPORTED_AUTO_ESCAPING_POLICY);

            // 3. Restrict object wrapper to prevent reflection access
            cfg.setNewBuiltinClassResolver(
                freemarker.core.TemplateClassResolver.SAFER_RESOLVER
            );

            // 4. Set template exception handler (don't expose errors)
            cfg.setTemplateExceptionHandler(
                TemplateExceptionHandler.RETHROW_HANDLER
            );

            // 5. Disable template updates (use preloaded templates only)
            cfg.setTemplateUpdateDelayMilliseconds(Integer.MAX_VALUE);

            return cfg;

        } catch (Exception e) {
            throw new RuntimeException("Failed to configure Freemarker", e);
        }
    }

    /**
     * Sanitize and validate template data
     */
    private Map<String, Object> sanitizeTemplateData(Map<String, Object> rawData) 
            throws IllegalArgumentException {

        Map<String, Object> sanitized = new HashMap<>();

        for (Map.Entry<String, Object> entry : rawData.entrySet()) {
            String key = entry.getKey();
            Object value = entry.getValue();

            // Whitelist check
            if (!allowedTemplateVars.contains(key)) {
                throw new IllegalArgumentException(
                    "Invalid template variable: " + key
                );
            }

            // Type validation (only primitives)
            if (!(value instanceof String || value instanceof Number)) {
                throw new IllegalArgumentException(
                    "Invalid value type for " + key
                );
            }

            // Check for injection attempts in string values
            if (value instanceof String) {
                String strValue = (String) value;
                if (TEMPLATE_INJECTION_PATTERN.matcher(strValue).matches()) {
                    throw new IllegalArgumentException(
                        "Template injection detected in " + key
                    );
                }
            }

            sanitized.put(key, value);
        }

        return sanitized;
    }

    /**
     * SECURE: Render email using preloaded template
     */
    @PostMapping("/email/render")
    public Map<String, String> renderEmail(@RequestBody Map<String, Object> requestData) {
        try {
            // Template name is hardcoded (NOT from user input)
            String templateName = "order_confirmation.ftl";

            // Sanitize input data
            Map<String, Object> templateData = sanitizeTemplateData(requestData);

            // Load precompiled template
            Template template = freemarkerConfig.getTemplate(templateName);

            // Render template
            StringWriter writer = new StringWriter();
            template.process(templateData, writer);

            return Map.of("html", writer.toString());

        } catch (IllegalArgumentException e) {
            throw new ResponseStatusException(
                HttpStatus.BAD_REQUEST, 
                "Invalid template data: " + e.getMessage()
            );
        } catch (IOException | TemplateException e) {
            throw new ResponseStatusException(
                HttpStatus.INTERNAL_SERVER_ERROR,
                "Template rendering failed"
            );
        }
    }

